  1→import {useLocation, useNavigate } from 'react-router-dom';
  2→import './profilepostcards.css';
  3→import { useInfiniteQuery } from '@tanstack/react-query';
  4→import { useEffect, useState, useCallback } from 'react';
  5→import { MoonLoader } from 'react-spinners';
  6→import { motion } from 'framer-motion';
  7→import ParseContent from '../parseData';
  8→import { useInView } from 'react-intersection-observer';
  9→import { handleCLickContent } from '../../../../../helpers/handleClicks';
 10→import { useAuth } from '../../../../Context/useAuth';
 11→import { getVisitedUserJournals } from '../../../../../API/Api';
 12→import { useAddViewsMutation } from '../../../../utils/useMutation';
 13→import VerifiedBadge from '../../../Badge/VerifiedBadge';
 14→import { handleImageFallback } from '../../../../utils/handleImageFallback';
 15→
 16→const VisitedProfilePostCards = () =>{
 17→    const location = useLocation();
 18→    const userId = location.state?.userId || new URLSearchParams(location.search).get('userId');
 19→    const {user, session} = useAuth();
 20→
 21→    const navigate = useNavigate();
 22→
 23→    const {ref, inView} = useInView({
 24→        threshold: 0.2
 25→    })
 26→
 27→    const {data: journalData, isLoading: isLoadingJournals, isFetchingNextPage, fetchNextPage, hasNextPage,} = useInfiniteQuery({
 28→        queryKey: ['visitedProfileJournals', userId, user?.userData?.[0]?.id],
 29→        queryFn: ({pageParam = null, queryKey}) => getVisitedUserJournals(pageParam, 5, queryKey[1], queryKey[2]),
 30→        getNextPageParam: (lastPage) => {
 31→            if(lastPage.hasMore){
 32→                const lastJournal = lastPage?.data[lastPage?.data.length - 1]
 33→                return new Date(lastJournal.created_at).toISOString();
 34→            } else {
 35→                return undefined
 36→            }
 37→        },
 38→        enabled: !!userId,
 39→        refetchOnWindowFocus: false,
 40→        staleTime: 1000 * 60 * 5
 41→    })
 42→
 43→    const clickContent = handleCLickContent(navigate);
 44→    const mutateViews = useAddViewsMutation(session);
 45→    const viewContent = (e, jsonbContent,wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likesCount, bookmarksCount, badge, postType = null, userReaction = null, reactionCount = 0) =>{
 46→        const formadata = new FormData();
 47→        formadata.append('journalId', journalId)
 48→        mutateViews.mutate(formadata);
 49→
 50→        clickContent(e, jsonbContent,wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likesCount, bookmarksCount, badge, postType, userReaction, reactionCount);
 51→    }
 52→
 53→    useEffect(() =>{
 54→        // console.log(userId)
 55→    },[userId])
 56→
 57→    const [viewMode, setViewMode] = useState('grid');
 58→
 59→    useEffect(() =>{
 60→        if(!isFetchingNextPage && hasNextPage && inView){
 61→            fetchNextPage();
 62→        }
 63→    }, [inView, fetchNextPage, isFetchingNextPage, hasNextPage])
 64→
 65→    const handleToggleView = useCallback(() => {
 66→        setViewMode((prev) => (prev === 'list' ? 'grid' : 'list'));
 67→    }, []);
 68→
 69→    const journals = journalData?.pages.flatMap((page) => page.data) || [];
 70→
 71→
 72→   if(isLoadingJournals){
 73→        return(
 74→            <>
 75→            <div className='profile-postcards-loading-container'>
 76→                <MoonLoader loading={isLoadingJournals} color="var(--loader-color)" size={20} speedMultiplier={0.5}/>
 77→            </div>
 78→            </>
 79→        )
 80→    }
 81→    
 82→
 83→    if(journalData && !journals?.length > 0){
 84→        return (
 85→            <div className='profile-postcards-loading-container'>
 86→                No post available!
 87→            </div>
 88→        )
 89→    }
 90→
 91→    return(
 92→        <>
 93→        <div className='profile-postcards-parent-container'>
 94→            <div className="postcards-header-row">
 95→                <h2 className="postcards-heading">
 96→                    Posts <span className="postcards-count">({journals.length})</span>
 97→                </h2>
 98→                <div className="postcards-header-actions">
 99→                    <button
100→                        className={`postcards-view-toggle-btn ${viewMode === 'grid' ? 'is-active' : ''}`}
101→                        onClick={handleToggleView}
102→                        title={viewMode === 'grid' ? 'Switch to list' : 'Switch to grid'}
103→                    >
104→                        {viewMode === 'grid' ? (
105→                            <svg xmlns="http://www.w3.org/2000/svg" height="20px" viewBox="0 -960 960 960" width="20px" fill="currentColor"><path d="M120-520v-320h320v320H120Zm0 400v-320h320v320H120Zm400-400v-320h320v320H520Zm0 400v-320h320v320H520Z"/></svg>
106→                        ) : (
107→                            <svg xmlns="http://www.w3.org/2000/svg" height="20px" viewBox="0 -960 960 960" width="20px" fill="currentColor"><path d="M120-200v-560h720v560H120Z"/></svg>
108→                        )}
109→                    </button>
110→                </div>
111→            </div>
112→
113→            {viewMode === 'grid' ? (
114→                <div className="postcards-grid-view">
115→                    {journals.map((journal) => {
116→                        const parsedContent = ParseContent(journal.content);
117→                        const wholeText = parsedContent?.wholeText || '';
118→                        const previewText = parsedContent?.slicedText || '';
119→                        const thumbnail = parsedContent?.firstImage?.src;
120→                        return (
121→                            <motion.div
122→                                key={journal.id}
123→                                className="postcards-grid-item"
124→                                initial={{ opacity: 0, scale: 0.95 }}
125→                                animate={{ opacity: 1, scale: 1 }}
126→                                transition={{ duration: 0.25, ease: 'easeOut' }}
127→                                onClick={(e) => viewContent(e, journal?.content, wholeText, journal?.title, userId, journal?.users?.name, journal?.users?.image_url, journal?.created_at, journal?.id, journal?.has_liked, journal?.comment_count?.[0].count, journal?.has_bookmarked, journal?.like_count?.[0].count, journal?.bookmark_count?.[0].count, journal?.users?.badge, journal?.post_type, journal?.user_reaction, journal?.reaction_count?.[0]?.count || 0)}
128→                            >
129→                                {thumbnail ? (
130→                                    <div className="postcards-grid-img-wrap">
131→                                        <img className="postcards-grid-thumb" src={thumbnail} alt={journal?.title ? `${journal.title} cover image` : "Post cover image"} loading="lazy" onError={handleImageFallback} />
132→                                    </div>
133→                                ) : null}
134→                                <div className="postcards-grid-body">
135→                                    <h3 className="postcards-grid-title">{journal.title.length > 32 ? `${journal.title.substring(0, 32)}...` : journal.title}</h3>
136→                                    {previewText && (
137→                                        <p className="postcards-grid-snippet">{previewText.length > 50 ? `${previewText.substring(0, 50)}...` : previewText}</p>
138→                                    )}
139→                                </div>
140→                            </motion.div>
141→                        );
142→                    })}
143→                </div>
144→            ) : (
145→            <div className="postcards-list-view">
146→            {journals.map((journal, index) => {
147→                const parsedContent = ParseContent(journal.content);
148→                const wholeText = parsedContent?.wholeText || '';
149→                const previewText = parsedContent?.slicedText || '';
150→                const thumbnail = parsedContent?.firstImage?.src;
151→                const badgeClass = journal.users.badge === 'legend' ? 'avatar-ring-legend' : journal.users.badge === 'og' ? 'avatar-ring-og' : '';
152→
153→                return(
154→                    <motion.div
155→                        key={journal.id || index}
156→                        className="profile-postcards"
157→                        initial={{opacity: 0, y: 12}}
158→                        animate={{opacity: 1, y: 0}}
159→                        transition={{duration: 0.3, ease: 'easeOut'}}
160→                    >
161→                        {thumbnail && (
162→                            <img
163→                                className="card-image-banner"
164→                                src={thumbnail}
165→                                alt={journal?.title ? `${journal.title} cover image` : "Post cover image"}
166→                                loading="lazy"
167→                                onError={handleImageFallback}
168→                                onClick={(e) => viewContent(e, journal?.content, wholeText, journal?.title, userId, journal?.users?.name, journal?.users?.image_url, journal?.created_at, journal?.id, journal?.has_liked, journal?.comment_count?.[0].count, journal?.has_bookmarked, journal?.like_count?.[0].count, journal?.bookmark_count?.[0].count, journal?.users?.badge, journal?.post_type, journal?.user_reaction, journal?.reaction_count?.[0]?.count || 0)}
169→                            />
170→                        )}
171→
172→                        <div className='user-profile-card-content'>
173→                            <div onClick={(e) => viewContent(e, journal?.content, wholeText, journal?.title, userId, journal?.users?.name, journal?.users?.image_url, journal?.created_at, journal?.id, journal?.has_liked, journal?.comment_count?.[0].count, journal?.has_bookmarked, journal?.like_count?.[0].count, journal?.bookmark_count?.[0].count, journal?.users?.badge, journal?.post_type, journal?.user_reaction, journal?.reaction_count?.[0]?.count || 0)} className="content-container">
174→                                <div className='feed-text-content-container'>
175→                                    <div className='feed-title-content'>
176→                                        <h2 className="feed-title-profile-page">{journal.title.length > 55 ? `${journal.title.substring(0, 55)}...` : journal.title}</h2>
177→                                    </div>
178→                                    <p className="feed-text-content-profile-page">{previewText}</p>
179→                                </div>
180→                            </div>
181→
182→                            <div className="card-icons-container">
183→                                <div className='user-info-child-container'>
184→                                    <div className={`user-avatar-container ${badgeClass}`}>
185→                                        <img src={journal.users.image_url || '/assets/profile.jpg'} alt="user-profile" loading='lazy' className="user-info-avatar"/>
186→                                    </div>
187→                                    <div className="user-name-container">
188→                                        <p className="user-newsfeed-name-profile-page">{journal.users.name}</p>
189→                                        <VerifiedBadge badge={journal.users.badge} size={14} />
190→                                    </div>
191→                                    <div className="name-info-separator">•</div>
192→                                    <p className="user-post-date">{new Date(journal.created_at).toLocaleDateString('en-US', {
193→                                        month: 'long',
194→                                        day: 'numeric',
195→                                        year: 'numeric'
196→                                    })}</p>
197→
198→                                    <div className="user-post-settings">
199→                                        <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="M240-400q-33 0-56.5-23.5T160-480q0-33 23.5-56.5T240-560q33 0 56.5 23.5T320-480q0 33-23.5 56.5T240-400Zm240 0q-33 0-56.5-23.5T400-480q0-33 23.5-56.5T480-560q33 0 56.5 23.5T560-480q0 33-23.5 56.5T480-400Zm240 0q-33 0-56.5-23.5T640-480q0-33 23.5-56.5T720-560q33 0 56.5 23.5T800-480q0 33-23.5 56.5T720-400Z"/></svg>
200→                                    </div>
201→                                </div>
202→                            </div>
203→                        </div>
204→                    </motion.div>
205→                )
206→            })}
207→            </div>
208→            )}
209→
210→            <div ref={ref} className='in-view-container'>
211→                {isFetchingNextPage && (
212→                    <MoonLoader size={20} color="var(--loader-color)" loading={isFetchingNextPage}/>
213→                )}
214→            </div>
215→
216→        </div>
217→        </>
218→    )
219→}
220→
221→export default VisitedProfilePostCards;
