 1→import ParseContent from "../postCards/parseData";
 2→import formatPostDate from "../../../../helpers/formatDateString";
 3→import { handleImageFallback } from "../../../utils/handleImageFallback";
 4→import "./interestSections.css";
 5→
 6→const InterestSections = ({ sections, onPostClick }) => {
 7→    if (!sections || sections.length === 0) return null;
 8→
 9→    return (
10→        <div className="interest-sections">
11→            {sections.map((section) => (
12→                <div key={section.interest} className="interest-section">
13→                    <div className="interest-section-header">
14→                        <span className="interest-section-title">
15→                            Trending in {section.interest}
16→                        </span>
17→                    </div>
18→                    <div className="interest-section-scroll">
19→                        {section.posts.map((post) => {
20→                            const parsed = ParseContent(post.content);
