588→                                                <p className="reading-time-text">{CalculateText(parsedContent?.wholeText)}</p>
589→                                            </div>
590→                                        </div>
591→                                    </div>
592→                                </motion.div>
593→                            ) : (
594→                                <RunnerCard
595→                                    key={journal.id}
596→                                    journal={journal}
597→                                    index={displayIndex}
598→                                    parsedContent={parsedContent}
599→                                    hotScore={hotScore}
600→                                    onClick={handleClickPost}
601→                                />
602→                            );
603→                        })}
604→                    </div>
605→                </div>
606→            )}
607→            </>
608→            )}
609→        </div>
610→    );
611→};
