270→                                </div>
271→
272→                                <div className="notification-content"
273→                                    onClick={(e) => handleReadNotif(e, unreadNotification)}
274→                                >
275→                                    {isOpinion ? (
276→                                        <div className="notification-content-text">
277→                                            <p className="notif-content-sliced-text">{unreadNotification?.opinions?.opinion?.length > 100 ? unreadNotification?.opinions?.opinion?.substring(0, 100) + '...' : unreadNotification?.opinions?.opinion}</p>
278→                                        </div>
279→                                    ) : (
280→                                        <>
281→                                        <div className="notification-content-text">
282→                                            <p className="notif-content-title">{unreadNotification?.journals?.title?.length > 40 ? unreadNotification?.journals?.title?.substring(0, 39) : unreadNotification?.journals?.title}</p>
283→                                            <p className="notif-content-sliced-text">{parsedContent?.slicedText}</p>
284→                                        </div>
285→                                        <div className="notif-content-image-container">
286→                                            <img className="notif-content-image" loading="lazy" src={parsedContent?.firstImage?.src || '/assets/no-image.png'} alt={unreadNotification?.journals?.title ? `${unreadNotification.journals.title} cover image` : "Notification post cover image"} onError={handleImageFallback} />
287→                                        </div>
288→                                        </>
289→                                    )}
290→                                </div>
291→                            </div>
292→                        </div>
293→
294→                    </div>
295→                )
296→            })}
297→            <div ref={inviewRef} className="notification-inview-container">
298→                {isFetchinNextPage && (
299→                    <MoonLoader loading={isFetchinNextPage} color="var(--loader-color)" size={20}/>
300→                )}
301→            </div>
302→        </div>
303→        </>
304→    )
305→}
